function isCovered(ranges, left, right) {
    for (let i = left; i <= right; i++) {
        let found = false;
        for (const range of ranges) {
            if (i >= range[0] && i <= range[1]) {
                found = true;
                break;
            }
        }
        if (!found) return false;
    }
    return true;
}
